text:
Section 1 — Compréhension de l’écrit
D’après le discours d’Emma Garcia sur le projet de végétalisation des Champs-Élysées (leçon du 10 juin).

viewof s1 = Inputs.form({
  q1: Inputs.radio(
    ["150 millions d'euros", "250 millions d'euros", "350 millions d'euros", "200 millions d'euros"],
    {label: "1. Quel est le budget du projet de végétalisation des Champs-Élysées ?"}
  ),
  q2: Inputs.radio(
    ["5 %", "50 %", "68 %", "80 %"],
    {label: "2. Quel pourcentage des visiteurs quotidiens des Champs-Élysées sont des touristes ?"}
  ),
  q3: Inputs.radio(
    ["1 000 véhicules", "2 000 véhicules", "3 000 véhicules", "5 000 véhicules"],
    {label: "3. Combien de véhicules passent actuellement sur l'avenue par heure ?"}
  ),
  q4: Inputs.radio(
    [
      "C'est le côté le plus fréquenté par les touristes",
      "C'est le côté où il y a toujours du soleil",
      "C'est le côté avec le plus de pollution",
      "C'est le côté historique de l'avenue"
    ],
    {label: "4. Pourquoi veut-on planter des arbres du côté des numéros pairs ?"}
  ),
  q5: Inputs.radio(
    ["Un", "Deux", "Trois", "Quatre"],
    {label: "5. Après 2024, combien de couloirs de circulation y aura-t-il dans chaque sens ?"}
  )
})

Section 2 — Vocabulaire
Choisissez la bonne définition ou le bon équivalent pour chaque expression du cours.

viewof s2 = Inputs.form({
  q6: Inputs.radio(
    [
      "Jeter un livre dans l'eau",
      "Lire un roman intensément",
      "Écrire un roman",
      "Acheter un roman"
    ],
    {label: "6. Que signifie « se plonger dans un roman » ?"}
  ),
  q7: Inputs.radio(
    [
      "Nettoyer un espace public",
      "Agrandir un espace urbain",
      "Planter des végétaux, arbres, des fleurs",
      "Peindre un espace en vert"
    ],
    {label: "7. Que signifie « végétaliser un espace » ?"}
  ),
  q8: Inputs.radio(
    ["atténuer", "entretenir", "prévenir", "augmenter"],
    {label: "8. Quel verbe du cours signifie « maintain » (maintenir) ?"}
  ),
  q9: Inputs.radio(
    [
      "La pollution visuelle",
      "Les mauvaises odeurs",
      "Le bruit qui dérange",
      "La circulation dense des voitures"
    ],
    {label: "9. Que désignent « les nuisances sonores » ?"}
  ),
  q10: Inputs.radio(
    [
      "Préparer un grand petit-déjeuner",
      "Se lever très tôt le matin",
      "Dormir tardivement le matin",
      "Faire du sport le matin"
    ],
    {label: "10. Que veut dire « faire la grasse matinée » ?"}
  )
})

Section 3 — Grammaire : La Négation
Choisissez la réponse négative correcte ou identifiez la phrase grammaticalement juste.

viewof s3 = Inputs.form({
  q11: Inputs.radio(
    [
      "Non, je ne suis pas venu",
      "Non, personne n'est venu",
      "Non, rien n'est venu",
      "Non, jamais je ne suis venu"
    ],
    {label: "11. « Est-ce que quelqu'un est venu ? » → Répondez négativement :"}
  ),
  q12: Inputs.radio(
    [
      "Non, je ne veux personne boire",
      "Non, je ne veux rien boire",
      "Non, je ne veux jamais boire",
      "Non, je ne veux ni boire"
    ],
    {label: "12. « Tu veux boire quelque chose ? » → Répondez négativement :"}
  ),
  q13: Inputs.radio(
    [
      "Rien ne se passent",
      "Rien ne se passe",
      "Rien ne se pas",
      "Ne rien se passe"
    ],
    {label: "13. Quelle phrase est grammaticalement correcte ?"}
  ),
  q14: Inputs.radio(
    [
      "Je ne vais ni à la mer ni à la montagne",
      "Je ne vais pas à la mer ni à la montagne",
      "Ni je vais à la mer ni à la montagne",
      "Je vais ni à la mer ni à la montagne"
    ],
    {label: "14. « Tu vas en vacances à la mer ou à la montagne ? » → Utilisez « ni...ni » :"}
  ),
  q15: Inputs.radio(
    [
      "Personne ne vient jamais",
      "Personne ne vient pas",
      "Ne personne vient jamais",
      "Personne vient ne jamais"
    ],
    {label: "15. Quelle phrase est correcte (deux négations combinées) ?"}
  ),
  q16: Inputs.radio(
    [
      "Non, il n'a rien rencontré",
      "Non, il n'a rencontré personne d'intéressant",
      "Non, il ne rencontre personne",
      "Non, personne n'a rencontré"
    ],
    {label: "16. « Il a rencontré quelqu'un d'intéressant ? » → Répondez négativement :"}
  )
})

Section 4 — Grammaire : Le Gérondif
Le gérondif = « en » + participe présent. Choisissez la bonne forme.

viewof s4 = Inputs.form({
  q17: Inputs.radio(
    [
      "en utilisant la lumière naturelle",
      "utilisant la lumière naturelle",
      "en utilise la lumière naturelle",
      "pour utiliser la lumière naturelle"
    ],
    {label: "17. Comment dit-on « by using natural light » en français ?"}
  ),
  q18: Inputs.radio(
    [
      "pour harmonisant les couleurs",
      "en harmonisant les couleurs",
      "par harmoniser les couleurs",
      "à harmonisant les couleurs"
    ],
    {label: "18. Complétez : « On peut réussir une décoration parfaite _______ les couleurs. »"}
  ),
  q19: Inputs.radio(
    [
      "En ayant du choix, on est content",
      "En avoir du choix, on est content",
      "Ayant en du choix, on est content",
      "En eu du choix, on est content"
    ],
    {label: "19. Quelle phrase utilise correctement le gérondif ?"}
  ),
  q20: Inputs.radio(
    [
      "a + infinitif",
      "pour + infinitif",
      "en + participe présent",
      "par + infinitif"
    ],
    {label: "20. Le gérondif se forme avec :"}
  )
})








viewof submitted = Inputs.button("✅ Soumettre le test", {
  value: 0,
  reduce: d =&gt; d + 1
})







{
  if (submitted === 0) {
    return html`
      &lt;div class="callout callout-style-default callout-tip"&gt;
        &lt;div class="callout-header d-flex align-content-center"&gt;
          &lt;div class="callout-icon-container"&gt;&lt;i class="callout-icon"&gt;&lt;/i&gt;&lt;/div&gt;
          &lt;div class="callout-title-container flex-fill"&gt;En attente de soumission&lt;/div&gt;
        &lt;/div&gt;
        &lt;div class="callout-body-container callout-body"&gt;
          &lt;p&gt;Répondez à toutes les questions ci-dessus, puis cliquez sur &lt;strong&gt;Soumettre le test&lt;/strong&gt;.&lt;/p&gt;
        &lt;/div&gt;
      &lt;/div&gt;`;
  }

  const correct = {
    q1:  "250 millions d'euros",
    q2:  "68 %",
    q3:  "3 000 véhicules",
    q4:  "C'est le côté où il y a toujours du soleil",
    q5:  "Deux",
    q6:  "Lire un roman intensément",
    q7:  "Planter des végétaux, arbres, des fleurs",
    q8:  "entretenir",
    q9:  "Le bruit qui dérange",
    q10: "Dormir tardivement le matin",
    q11: "Non, personne n'est venu",
    q12: "Non, je ne veux rien boire",
    q13: "Rien ne se passe",
    q14: "Je ne vais ni à la mer ni à la montagne",
    q15: "Personne ne vient jamais",
    q16: "Non, il n'a rencontré personne d'intéressant",
    q17: "en utilisant la lumière naturelle",
    q18: "en harmonisant les couleurs",
    q19: "En ayant du choix, on est content",
    q20: "en + participe présent"
  };

  const explanations = {
    q1:  "Emma Garcia précise que le budget « s'élève à 250 millions d'euros ».",
    q2:  "« 68% des 100 000 visiteurs quotidiens de l'avenue sont des touristes » (Emma Garcia).",
    q3:  "« Il y passe actuellement 3 000 véhicules par heure ! » (Emma Garcia).",
    q4:  "Le projet végétalise surtout « du côté des numéros pairs, c'est-à-dire le trottoir de droite quand on va vers l'Arc de Triomphe, où il y a du soleil tout le temps ».",
    q5:  "« Après 2024, il n'y aura que deux couloirs dans chaque sens de circulation » (Emma Garcia).",
    q6:  "« Se plonger dans » est une expression idiomatique qui signifie s'immerger complètement dans une activité — ici, lire de façon intensive.",
    q7:  "Du cours (10 juin) : « La végétalisation = végétaliser un espace = planter des végétaux, arbres, des fleurs, des arbustes ».",
    q8:  "Du lexique (9 juin) : « Elle entretient + nom (maintain) ». Exemples : entretenir la forme, entretenir l'amitié.",
    q9:  "Du lexique de l'aménagement urbain (11 juin) : « réduire les nuisances sonores (le bruit, un quartier bruyant) ».",
    q10: "« Faire la grasse matinée » = rester au lit plus longtemps que d'habitude, se lever tard. Du lexique vacances (10 juin).",
    q11: "Quand « quelqu'un » est sujet, la négation se place en tête : « Personne n'est venu ». Structure : Personne ne + verbe.",
    q12: "Quand « quelque chose » est objet, on utilise « ne...rien » : « Je ne veux rien boire ». Structure : ne + verbe + rien (à l'infinitif).",
    q13: "« Rien » sujet exige « ne » avant le verbe (accord au singulier) : « Rien ne se passe ». Les autres formes sont agrammaticales.",
    q14: "Structure ni...ni : « Je ne vais ni à la mer ni à la montagne ». Le « ne » reste obligatoire avec le verbe.",
    q15: "On peut combiner « personne » et « jamais » : « Personne ne vient jamais ». Avec « personne » sujet, on ne peut pas ajouter « pas ».",
    q16: "« Quelqu'un » objet → « personne » après le verbe : « il n'a rencontré personne d'intéressant ». L'adjectif suit « personne de ».",
    q17: "Gérondif de « utiliser » : utiliser → utilisant → en utilisant. Structure : en + participe présent.",
    q18: "Gérondif de « harmoniser » : harmoniser → harmonisant → en harmonisant. Du cours (12 juin) : « en utilisant bien de la lumière ».",
    q19: "Gérondif de « avoir » : avoir → ayant → en ayant. La phrase « En ayant du choix, on est content » est la seule forme correcte.",
    q20: "Le gérondif = invariable, formé avec « en » + participe présent (radical + -ant). Ex. : prendre → prenant → en prenant."
  };

  const labels = {
    q1:  "1. Budget du projet",
    q2:  "2. Pourcentage de touristes",
    q3:  "3. Véhicules par heure",
    q4:  "4. Côté des numéros pairs",
    q5:  "5. Couloirs après 2024",
    q6:  "6. Se plonger dans",
    q7:  "7. Végétaliser",
    q8:  "8. Maintenir",
    q9:  "9. Nuisances sonores",
    q10: "10. Grasse matinée",
    q11: "11. Quelqu'un est venu ?",
    q12: "12. Boire quelque chose ?",
    q13: "13. Phrase correcte (rien)",
    q14: "14. Mer ou montagne ?",
    q15: "15. Double négation",
    q16: "16. Quelqu'un d'intéressant ?",
    q17: "17. By using…",
    q18: "18. Gérondif – harmoniser",
    q19: "19. Gérondif – avoir",
    q20: "20. Formation du gérondif"
  };

  const allKeys = Object.keys(correct);
  const userAnswers = {...s1, ...s2, ...s3, ...s4};

  const sections = [
    { name: "Compréhension de l'écrit", keys: ["q1","q2","q3","q4","q5"], max: 5 },
    { name: "Vocabulaire",              keys: ["q6","q7","q8","q9","q10"], max: 5 },
    { name: "La Négation",              keys: ["q11","q12","q13","q14","q15","q16"], max: 6 },
    { name: "Le Gérondif",              keys: ["q17","q18","q19","q20"], max: 4 }
  ];

  let totalScore = 0;
  const sectionResults = sections.map(sec =&gt; {
    const score = sec.keys.filter(k =&gt; userAnswers[k] === correct[k]).length;
    totalScore += score;
    return { ...sec, score };
  });

  const pct = Math.round((totalScore / 20) * 100);
  const grade =
    pct &gt;= 80 ? "Excellent !" :
    pct &gt;= 60 ? "Bien" :
    pct &gt;= 40 ? "Passable" : "À retravailler";
  const gradeColor =
    pct &gt;= 80 ? "#166534" :
    pct &gt;= 60 ? "#1d4ed8" :
    pct &gt;= 40 ? "#b45309" : "#991b1b";

  return html`
    &lt;div style="font-family:'EB Garamond',serif; max-width:700px; line-height:1.6;"&gt;

      &lt;h2 style="border-bottom:2px solid #e5e7eb; padding-bottom:.5rem; margin-top:1rem;"&gt;
        📊 Résultats
      &lt;/h2&gt;

      &lt;div style="background:#f8f9fa; border-radius:12px; padding:1.5rem; margin:1rem 0; text-align:center;"&gt;
        &lt;div style="font-size:3rem; font-weight:700; color:${gradeColor};"&gt;${totalScore} / 20&lt;/div&gt;
        &lt;div style="font-size:1.4rem; color:${gradeColor}; margin-top:.25rem;"&gt;${grade} — ${pct} %&lt;/div&gt;
      &lt;/div&gt;

      &lt;div style="display:grid; grid-template-columns:repeat(2,1fr); gap:.75rem; margin:1rem 0;"&gt;
        ${sectionResults.map(s =&gt; {
          const c = s.score === s.max ? "#166534" : s.score &gt;= s.max / 2 ? "#1d4ed8" : "#991b1b";
          return html`
            &lt;div style="background:#f8f9fa; border-radius:8px; padding:.75rem 1rem;"&gt;
              &lt;div style="font-size:.85rem; color:#6b7280;"&gt;${s.name}&lt;/div&gt;
              &lt;div style="font-size:1.3rem; font-weight:700; color:${c};"&gt;${s.score} / ${s.max}&lt;/div&gt;
            &lt;/div&gt;`;
        })}
      &lt;/div&gt;

      &lt;h3 style="margin-top:1.5rem;"&gt;Corrections détaillées&lt;/h3&gt;

      ${allKeys.map(k =&gt; {
        const ok = userAnswers[k] === correct[k];
        const userVal = userAnswers[k] || "(sans réponse)";
        return html`
          &lt;div style="
            border-left:4px solid ${ok ? "#16a34a" : "#dc2626"};
            background:${ok ? "#f0fdf4" : "#fef2f2"};
            padding:.7rem 1rem;
            margin:.5rem 0;
            border-radius:0 8px 8px 0;
          "&gt;
            &lt;div style="font-weight:700; margin-bottom:.2rem;"&gt;
              ${ok ? "✅" : "❌"} ${labels[k]}
            &lt;/div&gt;
            ${ok
              ? html`&lt;div style="color:#16a34a; font-size:.9rem;"&gt;&lt;em&gt;${correct[k]}&lt;/em&gt;&lt;/div&gt;`
              : html`
                &lt;div style="color:#dc2626; font-size:.9rem;"&gt;Votre réponse : &lt;em&gt;${userVal}&lt;/em&gt;&lt;/div&gt;
                &lt;div style="color:#16a34a; font-size:.9rem;"&gt;Bonne réponse : &lt;em&gt;${correct[k]}&lt;/em&gt;&lt;/div&gt;`
            }
            &lt;div style="color:#374151; font-size:.85rem; margin-top:.3rem; font-style:italic;"&gt;
              ${explanations[k]}
            &lt;/div&gt;
          &lt;/div&gt;`;
      })}

    &lt;/div&gt;`;
}
